@module tuning  src=tuning.lua  loc=457  sha=d013d39  mode=namespace  self=tuning

# Invariants & contracts
  @invariant  pure coordinate-system module: no module state, no take state, no pb / detune realisation logic  @ 4
  @invariant  intent / realisation split — owns intent (cents-typed detune); pb realisation is tm's domain  @ 5
  @invariant  detune is cents throughout; raw 14-bit pb conversion is tm's flush boundary, never here  @ 6
  @invariant  cents[1] is the unison (0); nameless step displays as degree-octave via stepToText  @ 7
  @invariant  octave parameters are MIDI-relative (C4 → 4), not period-index  @ 8

# Shapes
  @shape  Temper = {name, periodPitch=token, pitches=token[ascending], stepNames=string[], periodAsStep=bool, cents=number[derived], period=cents[derived], octaveStep=int, octaveWidth=int, cellWidth=int}  @ 9

# Module-level constants
  @const tuning = {}  @ 10
  @const RATIO_CAP = 1 << 40  @ 314

# Private functions
  -- Temperament presets
  @fn computeOctaveStep(stepNames, n)  @ 16-22
      -- octaveStep: first step whose label reads as the next octave's C. Scans from
      -- the end for the last non-C name; nameless scale → bump at period (n+1).
  @fn octaveLabel(o)  @ 26-28
      -- Octave -1 renders as "M" so the bottom (the cents-0 anchor) stays one char,
      -- matching MIDI's C-1. See docs/tuning.md § Addressable range.
  @fn octaveFieldWidth(temper)  @ 32-34
      -- octaveFieldWidth: char width of the octave field, fixed by the top of the
      -- natural [0,12700]¢ range (floor at -1 ⇒ "M"). See docs/tuning.md § Display.
  @fn computeCellWidth(temper)  @ 37-46
      -- cellWidth: widest step label + the octave field; see docs/tuning.md § Display.
  @fn edo(n, names)  @ 86-95
  -- Scala import
  -- Generators
  @fn gcd(a, b)  @ 259
  @fn combinations(n, k)  @ 262-270
      -- Every k-subset of 1..n as a list of 1-based index lists.
  @fn reduceCents(c, period)  @ 301-303
      -- Reduce a cents value into [0, period).
  @fn asRatio(token)  @ 305-310
  @fn stackRatio(gn, gd, pn, pd, k)  @ 315-326
  @fn stepSpectrum(g, p, n)  @ 330-344
      -- Adjacent step sizes (incl. the wrap step) of an n-note chain of `g`
      -- reduced into `p`: {cents, count} per distinct size, large first.

# Public API (tuning.*)
  @api tuning.scalaPitch(token)  @ 49-67
      @contract  token → cents or nil: n/d, int, '.'=cents, n\m, n\m<equave> step (equave dflt 2/1).  @ 48
  @api tuning.derive(temper)  @ 70-84
      @contract  pitches→cents, periodPitch→period; stamps octaveStep + cellWidth. Pure; returns temper.  @ 69
  @api tuning.findTemper(name, userLib)  @ 120-123
      @contract  userLib first, then presets; nil when unknown to both; '12EDO' resolves via presets  @ 119
  @api tuning.parseScalaPitches(text)  @ 129-136
      -- Lenient: every non-blank, non-'!' line is a pitch token. Drives paste + the
      -- import Create button (which re-parses the box after any manual edits).
  @api tuning.parseScalaFile(text)  @ 140-154
      -- Strict .scl: drop '!' comment lines, then [description, count, pitch x count].
      -- Returns pitch tokens + description (suggested name) for the Scala load path.
  @api tuning.scalaToTemper(pitchLines, name)  @ 158-176
      -- Bridge Scala's convention (unison implicit, period last) to Continuum's
      -- (step 1 = 1/1, period separate): prepend unison, split off final as period.
  @api tuning.edoDegrees(spec, mode)  @ 182-199
      -- Equal-division subset spec -> ascending degrees; largest is the period.
      -- 'relative': cumulative step counts. 'absolute': sorted+deduped. nil on bad token.
  @api tuning.degreesToSpec(degrees, mode)  @ 203-208
      -- Inverse of edoDegrees: render a degree list back as a spec string in `mode`.
      -- Lets a mode switch convert the in-flight pattern rather than reset it.
  @api tuning.genEqual(degrees, interval)  @ 212-218
      -- N-equal-divisions of `interval` subset to `degrees`; tokens are intensional
      -- (d\D<equave>, suffix omitted for octave). Base 0 implicit; last degree = period.
  @api tuning.genHarmonics(lo, hi)  @ 222-226
      -- Harmonic-series segment lo..hi: ratios m/lo rooted on the low harmonic, the
      -- top (hi/lo) the period.
  @api tuning.genSubharmonics(lo, hi)  @ 229-233
      -- Subharmonic (utonal) segment lo..hi: ratios hi/m ascending, top the period.
  @api tuning.parseChord(spec)  @ 237-246
      -- Colon/space-separated extended ratio (e.g. '4:5:6:7') -> positive integers,
      -- at least two. nil + message otherwise.
  @api tuning.genChord(members, invert)  @ 250-257
      -- Enumerate a chord as a scale rooted on its first note. otonal: ci/c1.
      -- inverted (utonal): ck/c(k+1-i). The last member is the period either way.
  @api tuning.genCPS(factors, k, equave)  @ 274-298
      -- Combination product set: every k-subset's product, rooted on the smallest
      -- product (so 1/1 is always present) and reduced into the equave; ascending.
  @api tuning.genRank2(generator, period, size, up)  @ 348-367
      -- Rank-2 scale: stack the generator `up` above and `size-1-up` below 1/1,
      -- reduce into period, sort. up = mode. Exact ratios if inputs rational, else cents.
  @api tuning.mosInfo(generator, period, n)  @ 370-374
      @contract  {isMos, large, small} for an n-note chain; large/small are L/s step counts when isMos  @ 369
  @api tuning.nextMosSize(generator, period, fromN, dir)  @ 377-385
      @contract  next MOS size (two step sizes) from fromN, stepping dir (+/-1); nil past the cap  @ 376
  -- Coordinate conversions
  @api tuning.midiToStep(temper, midi, detune)  @ 391-410
      @contract  detune optional (defaults 0); snaps to nearest scale point including the period boundary (rounds up to step 1 of next octave)  @ 389
      @contract  returned octave is MIDI-relative (C-1 → -1)  @ 390
  @api tuning.stepToMidi(temper, step, octave)  @ 413-429
      @contract  wraps out-of-range step by adjusting octave; clamps midi to 0..127 by folding overflow into detune (never silently drops)  @ 412
  @api tuning.snap(temper, midi, detune)  @ 431-433
  @api tuning.transposeStep(temper, midi, detune, n)  @ 436-439
      @contract  moves by n scale steps under temper, carrying the octave; n may be negative  @ 435
  -- Display
  @api tuning.stepToParts(temper, step, octave)  @ 444-449
      @contract  returns (note, octaveLabel); named ⇒ name, nameless ⇒ degree+'-'; octave+1 at octaveStep  @ 443
  @api tuning.stepToText(temper, step, octave)  @ 452-455
      @contract  name ⇒ name+octave (C-4); blank/absent ⇒ degree-octave (7-4). Octave +1 at octaveStep.  @ 451

